#[cfg(test)]
mod city_name_tests {
    use super::*;

    #[test]
    fn every_civilization_has_a_deep_unique_city_name_pool() {
        for civilization in CIV_NAMES {
            let names = city_names(civilization);
            assert!(
                names.len() >= 16,
                "{civilization} should not exhaust its city names in a long standard game"
            );
            assert_eq!(
                names.iter().copied().collect::<BTreeSet<_>>().len(),
                names.len(),
                "{civilization} city names should be unique"
            );
        }
    }
}

#[cfg(test)]
fn install_test_district(game: &mut Game, city: u32, district: &str) -> Pos {
    let center = game.cities[&city].pos;
    let position = game.cities[&city]
        .owned_tiles
        .iter()
        .copied()
        .find(|position| {
            *position != center
                && game.map.tiles[position].district.is_none()
                && game.map.tiles[position].wonder.is_none()
                && game.map.tiles[position].improvement.is_none()
        })
        .expect("test city has an unused district tile");
    let tile = game.map.tiles.get_mut(&position).unwrap();
    tile.district = Some(district.to_string());
    tile.pillaged = false;
    game.cities
        .get_mut(&city)
        .unwrap()
        .districts
        .insert(district.to_string(), position);
    position
}

